// Collect workflow data
const webhookData = $('Webhook Trigger').first().json.body || {};
const referenceData = $('Load Reference Documents').first().json;

// Get reference documents
const frameworkDoc = referenceData.framework_taxonomy;
const questionDoc = referenceData.question_bank;

// Check if personality data exists BEFORE loading personality doc
const hasPersonalityData = !!webhookData.user_context?.personality?.type;
const personalityDoc = hasPersonalityData ? referenceData.personality_calibration : null;

const userContext = webhookData.user_context || null;

// Helper: Build user context
function buildUserContext(ctx) {
    if (!ctx) return '';

    const parts = [];
    const loc = ctx.location;
    const prof = ctx.professional;
    const team = ctx.team;
    const pref = ctx.preferences;

    if (loc?.country) {
        parts.push(
            `Location: ${loc.country}${loc.city ? ` (${loc.city})` : ''}`
        );
        if (loc.timezone) parts.push(`TZ: ${loc.timezone}`);
        if (loc.currency) parts.push(`Currency: ${loc.currency}`);
        if (loc.language) parts.push(`Lang: ${loc.language}`);
    }

    if (prof?.job_title || prof?.industry) {
        const p = [
            prof.job_title,
            prof.industry && `in ${prof.industry}`,
            prof.experience_level && `(${prof.experience_level})`
        ].filter(Boolean);
        if (p.length) parts.push(`Professional: ${p.join(' ')}`);
        if (prof.company_size) parts.push(`Company: ${prof.company_size}`);
    }

    if (team?.size || team?.role) {
        const t = [
            team.size && `${team.size} team`,
            team.role && `${team.role} role`,
            team.work_mode && `(${team.work_mode})`
        ].filter(Boolean);
        if (t.length) parts.push(`Team: ${t.join(', ')}`);
    }

    if (pref?.budget) parts.push(`Budget: ${pref.budget}`);
    if (pref?.primary_programming_language)
        parts.push(`Lang: ${pref.primary_programming_language}`);

    return parts.length
        ? '\n\n# User Context\n- ' +
        parts.join('\n- ') +
        '\n\nUse this context for framework/question recommendations.'
        : '';
}

const userContextString = buildUserContext(userContext);

// Language instructions (concise, token-efficient)
const languageCode = userContext?.location?.language || 'en-GB';
const languageMap = {
    'en-US': 'American English: Use American spelling (optimized, not optimised), MM/DD/YYYY dates, American terminology.',
    'en-GB': 'British English: Use British spelling (optimised, not optimized), DD/MM/YYYY dates, British terminology.',
    'fr': 'Français: Répondez en français. Conventions de ponctuation françaises (espace avant «!», «?»), dates au format JJ/MM/AAAA.',
    'de': 'Deutsch: Antwortet auf Deutsch. Deutsche Konventionen (Datumsformat TT.MM.JJJJ), Kommas als Dezimaltrennzeichen.',
    'es': 'Español: Responde en español. Convenciones españolas (fechas DD/MM/AAAA), puntuación y terminología.'
};
const languageInstructions = `\n\n# Language & Conventions\n${languageMap[languageCode] || languageMap['en-GB']}`;

// Check for forced framework
const forcedFrameworkCode = webhookData.forced_framework_code || null;
const frameworkInstructions = forcedFrameworkCode
    ? `\n## FORCED FRAMEWORK: ${forcedFrameworkCode}\nYou MUST use ${forcedFrameworkCode} as selected_framework. Generate questions specific to it. Do NOT select a different framework.\n`
    : `\n## FRAMEWORK SELECTION

Select the most appropriate framework by:

1. **Identify candidate frameworks** for the task's primary category
2. **Evaluate framework fit** based on:
   - How well the framework's components match the task's cognitive requirements
   - Whether the framework naturally supports the type of thinking needed
   - The framework's complexity relative to task complexity
3. **Select the best-fit framework**
4. **Explain in plain English**: Write a rationale in second person explaining why this framework suits your task

**Rationale Guidelines:**
- Address the user directly (use "you" and "your")
- Explain which aspects of the framework match the task needs
- Keep it clear and jargon-free
- NO mention of scoring, points, or numerical metrics
- Focus on WHY this framework helps accomplish the task

**Example rationale:**
"We've chosen the COAST framework for your strategy task because it naturally guides you through defining your vision (Context), setting clear objectives (Objective), and then working through the practical actions and tactics needed. This structured approach helps ensure you cover both the big-picture thinking and detailed execution planning your strategy requires."`

// Build system prompt - conditionally include personality calibration only if data exists
const personalitySection = hasPersonalityData && personalityDoc
    ? `\n\n## PERSONALITY CALIBRATION\n${personalityDoc.content}`
    : '';

const systemPrompt = `You analyze requests, classify tasks, identify cognitive requirements, select frameworks, perform Task-Trait Alignment, and generate questions. Return JSON only.${languageInstructions}

## FRAMEWORK TAXONOMY
${frameworkDoc.content || 'Not available'}${personalitySection}

## QUESTION BANK
${questionDoc.content || 'Not available'}

---

## TASK
1. Classify task (primary/secondary category from taxonomy)
   - If pre-analysis context provided: use task + context for classification
2. Identify cognitive requirements
${frameworkInstructions}
4. Select framework (explain fit in second-person plain English - NO scoring)
5. Perform Task-Trait Alignment (if personality data):
   - AMPLIFY aligned traits (leverage strengths)
   - COUNTERBALANCE opposing traits (inject requirements)
   - NEUTRAL for unrelated traits
5. Exclude questions based on pre-analysis context:
   - Skip "what type" if subject known
   - Skip "why" if purpose known
   - Skip "how detailed" if detail level known
6. Generate tailored questions
   - REFERENCE questions by their order (Q1, Q2, Q3, etc.) not by codes
   - EXPLAIN in second person what each question helps you clarify
   - USE plain English without Cognitive Requirement names or codes
   - Create a brief rationale explaining how these questions together help clarify your task${forcedFrameworkCode ? ' for ' + forcedFrameworkCode : ''}:
   - PRIORITISE questions that address identified cognitive requirements
   - Use "Cognitive Reqs" column in question bank to match questions to requirements
   - Ensure at least 1 question addresses each PRIMARY cognitive requirement
   - Balance: include universal + framework-specific + category-specific questions${hasPersonalityData ? '\n7. Apply personality calibration to phrasing/quantity' : ''}

## OUTPUT FORMAT
Return ONLY valid JSON (no markdown, no extra text):

\`\`\`json
{
  "task_classification": {
    "primary_category": "CODE",
    "secondary_category": null,
    "complexity": "simple|moderate|complex",
    "classification_reasoning": "Brief explanation",
    "content_type": "For CREATION_CONTENT only"
  },
  "cognitive_requirements": {
    "primary": ["REQ_CODE"],
    "secondary": ["REQ_CODE"],
    "reasoning": "Why these apply"
  },
  "selected_framework": {
    "name": "Name",
    "code": "FRAMEWORK_CODE",
    "components": ["C1", "C2"],
    "rationale": "Second-person explanation of why this framework suits the task (plain English, no scoring)"
  },
  "alternative_frameworks": [{"name": "Alt", "code": "CODE", "when_to_use_instead": "Condition"}],
  "personality_tier": "full|partial|none",
  "task_trait_alignment": {
    "NOTE": "ONLY include user's actual traits, not hypothetical",
    "amplified": [{"trait": "Actual trait from user data", "requirement_aligned": "CODE", "reason": "Why helps"}],
    "counterbalanced": [{"trait": "Actual trait", "requirement_opposed": "CODE", "reason": "Why blind spot", "injection": "Specific requirement to add to the prompt"}],
    "neutral": [{"trait": "Actual trait", "reason": "Why irrelevant"}]
  },
  "personality_adjustments_preview": ["AMPLIFIED: desc", "COUNTERBALANCED: desc"],
  "clarifying_questions": [{"id": "Q1", "question": "Text", "purpose": "Plain English explanation of what this question helps clarify for you (do not mention question codes or requirement names)", "required": true}],
  "question_rationale": "Explain how the questions help you. Reference questions by their order (Q1, Q2 etc.) and describe in plain language what each one helps clarify, without using question codes or requirement names."
}
\`\`\``;

// Build personality info
let personalityInfo =
    'No personality data. Skip Task-Trait Alignment, use neutral defaults.';

if (hasPersonalityData) {
    const p = webhookData.user_context.personality;
    personalityInfo = `Type: ${p.type}`;

    if (p.trait_percentages) {
        const typeLetters = p.type.split('-');
        const mainType = typeLetters[0];
        const identity = typeLetters[1];
        const t = p.trait_percentages;
        const traits = [];

        if (t.mind !== undefined) traits.push(`${mainType[0]} (${t.mind}%)`);
        if (t.energy !== undefined)
            traits.push(`${mainType[1]} (${t.energy}%)`);
        if (t.nature !== undefined)
            traits.push(`${mainType[2]} (${t.nature}%)`);
        if (t.tactics !== undefined)
            traits.push(`${mainType[3]} (${t.tactics}%)`);
        if (t.identity !== undefined)
            traits.push(`${identity} (${t.identity}%)`);

        personalityInfo += `\nTraits: ${traits.join(', ')}\nAnalyze ONLY these traits. For each: AMPLIFIED, COUNTERBALANCED, or NEUTRAL.`;
    } else {
        personalityInfo +=
            '\nPercentages: Not provided (use 65% default)\nPerform Task-Trait Alignment with defaults.';
    }
}

// Helper: Extract display value from pre-analysis context
// Values can be either:
// - Strings (inferred directly): "Database indexing..."
// - Objects with {question, answer, answer_label?} (user-provided): {answer: "users cannot reset password"}
function extractContextValue(value) {
    if (value === null || value === undefined) return null;
    if (typeof value === 'string') return value;
    if (typeof value === 'object') {
        // Prefer answer_label (formatted choice) over answer (raw value)
        if (value.answer_label) return value.answer_label;
        if (value.answer !== undefined) return value.answer;
    }
    return null;
}

// Build pre-analysis section
const preAnalysisContext = webhookData.pre_analysis_context || null;
let preAnalysisSection = '';

if (preAnalysisContext && Object.keys(preAnalysisContext).length > 0) {
    const contextLines = [];

    const subject = extractContextValue(preAnalysisContext.subject);
    const audience = extractContextValue(preAnalysisContext.audience);
    const purpose = extractContextValue(preAnalysisContext.purpose);
    const outputFormat = extractContextValue(preAnalysisContext.output_format);
    const detailLevel = extractContextValue(preAnalysisContext.detail_level);

    if (subject) contextLines.push(`- **Subject:** ${subject}`);
    if (audience) contextLines.push(`- **Audience:** ${audience}`);
    if (purpose) contextLines.push(`- **Purpose:** ${purpose}`);
    if (outputFormat) contextLines.push(`- **Output Format:** ${outputFormat}`);
    if (detailLevel) contextLines.push(`- **Detail Level:** ${detailLevel}`);

    if (contextLines.length > 0) {
        preAnalysisSection = '\n\n**Pre-Analysis Context (Already Clarified):**\n' + contextLines.join('\n');
        preAnalysisSection += '\n\n**Avoid Duplicate Questions:**\n- DO NOT ask about information already provided\n- Generate ONLY new questions not covered above';
        preAnalysisSection += '\n\n**For Task-Trait Alignment:**\n- If audience="self" → Full personality optimization\n- If audience=external → Still apply but note "creating for others"';
    }
}

// Build user message
let userMessage = `Task: ${webhookData.task_description || 'No task'}${preAnalysisSection}\n\n**Personality:** ${personalityInfo}`;

if (forcedFrameworkCode) {
    userMessage += `\n\n**FORCED FRAMEWORK:** ${forcedFrameworkCode}\nMUST use this. Generate specific questions for it.${userContextString}`;
}

return [
    {
        json: {
            system: systemPrompt,
            messages: [{ role: 'user', content: userMessage }]
        }
    }
];

