parameters.jsCode:
const apiResponse = $input.first().json;
const executionId = $execution.id || 'unknown';
const currentNode = 'Format Response';

let analysisData;
try {
  // Extract text from Anthropic API response
  let content = apiResponse.content?.[0]?.text || '';

  if (!content) {
    throw new Error('No content in API response');
  }

  // Remove any markdown code blocks if present
  content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  // Claude sometimes generates JSON multiple times with explanation text in between
  // Find ALL JSON objects and take the LAST one (most complete)
  const jsonObjects = [];
  let depth = 0;
  let jsonStart = -1;

  for (let i = 0; i < content.length; i++) {
    if (content[i] === '{') {
      if (depth === 0) jsonStart = i;
      depth++;
    } else if (content[i] === '}') {
      depth--;
      if (depth === 0 && jsonStart !== -1) {
        jsonObjects.push(content.substring(jsonStart, i + 1));
        jsonStart = -1;
      }
    }
  }

  if (jsonObjects.length === 0) {
    throw new Error('No JSON object found in response');
  }

  // Take the last JSON object (most complete)
  const jsonOnly = jsonObjects[jsonObjects.length - 1];

  // Try to parse JSON
  analysisData = JSON.parse(jsonOnly);

} catch (e) {
  // Enhanced error context for debugging
  const errorType = e.message.includes('No content') ? 'api_error' : 'parsing_error';
  const failedNode = e.message.includes('No content') ? 'Call Anthropic API' : currentNode;

  return [{
    json: {
      success: false,
      data: null,
      api_usage: null,
      error: {
        message: 'Failed to parse LLM response',
        details: e.message
      },
      error_context: {
        error_type: errorType,
        failed_node: failedNode,
        execution_id: executionId,
        timestamp: new Date().toISOString()
      }
    }
  }];
}

// Extract API usage data
const apiUsage = {
  model: apiResponse.model || 'claude-haiku-4-5',
  input_tokens: apiResponse.usage?.input_tokens || 0,
  output_tokens: apiResponse.usage?.output_tokens || 0
};

return [{
  json: {
    success: true,
    data: analysisData,
    api_usage: apiUsage,
    error: null
  }
}];
